return (
  <HeadlessButton
    className={(args) =>
      clsx(
        'transition',
        args.focus && 'nextra-focusable',
        variant === 'outline' && [
          'border border-gray-300 dark:border-neutral-700',
          'rounded-md p-1.5'
        ],
        typeof className === 'function' ? className(args) : className
      )
    }
    {...props}
  />
);

return (
  <nav style={{display: 'flex', gap: 10}}>
    <NavigationLink href="/">{t('home')}</NavigationLink>
    <NavigationLink href="/client">{t('client')}</NavigationLink>
    <NavigationLink href="/about">{t('about')}</NavigationLink>
    <NavigationLink href="/nested">{t('nested')}</NavigationLink>
    <NavigationLink
      href={{pathname: '/news/[articleId]', params: {articleId: 3}}}
    >
      {t('newsArticle', {articleId: String(3)})}
    </NavigationLink>
  </nav>
);

if (domain) {
  localePrefixes.sort(([localeA], [localeB]) => {
    if (localeA === domain.defaultLocale) return -1;
    if (localeB === domain.defaultLocale) return 1;

    const isLocaleAInDomain = domain.locales.includes(localeA);
    const isLocaleBInDomain = domain.locales.includes(localeB);
    if (isLocaleAInDomain && !isLocaleBInDomain) return -1;
    if (!isLocaleAInDomain && isLocaleBInDomain) return 1;

    return 0;
  });
}

const NavigationMenuList = React.forwardRef<
  React.ElementRef<typeof NavigationMenuPrimitive.List>,
  React.ComponentPropsWithoutRef<typeof NavigationMenuPrimitive.List>
>(({ className, ...props }, ref) => (
  <NavigationMenuPrimitive.List
    ref={ref}
    className={cn(
      "group flex flex-1 list-none items-center justify-center space-x-1",
      className
    )}
    {...props}
  />
))

const NavigationMenu = React.forwardRef<
  React.ElementRef<typeof NavigationMenuPrimitive.Root>,
  React.ComponentPropsWithoutRef<typeof NavigationMenuPrimitive.Root>
>(({ className, children, ...props }, ref) => (
  <NavigationMenuPrimitive.Root
    ref={ref}
    className={cn(
      "relative z-10 flex max-w-max flex-1 items-center justify-center",
      className
    )}
    {...props}
  >
    {children}
    <NavigationMenuViewport />
  </NavigationMenuPrimitive.Root>
))

React.useEffect(() => {
    if (refetchInterval && shouldRefetch) {
      const refetchIntervalTimer = setInterval(() => {
        if (__NEXTAUTH._session) {
          __NEXTAUTH._getSession({ event: "poll" })
        }
      }, refetchInterval * 1000)
      return () => clearInterval(refetchIntervalTimer)
    }
  }, [refetchInterval, shouldRefetch])

try {
  const pkg = JSON.parse(fs.readFileSync(pkgJsonPath))
  exec("git rev-parse --short HEAD", (err, stdout) => {
    if (err) {
      console.log(err)
      process.exit(1)
    }
    pkg.version = "0.0.0-next." + stdout.trim()
    fs.writeFileSync(pkgJsonPath, JSON.stringify(pkg, null, "\t") + "\n")
  })
} catch (error) {
  console.error(error)
  process.exit(1)
}

return (
  <Suspense fallback={<SquareIcon {...props} />}>
    {iconLibrary === "lucide" && <IconLucide name={iconName} {...props} />}
    {iconLibrary === "tabler" && <IconTabler name={iconName} {...props} />}
    {iconLibrary === "hugeicons" && (
      <IconHugeicons name={iconName} {...props} />
    )}
    {iconLibrary === "phosphor" && (
      <IconPhosphor name={iconName} {...props} />
    )}
    {iconLibrary === "remixicon" && (
      <IconRemixicon name={iconName} {...props} />
    )}
  </Suspense>
)

React.useEffect(() => {
    const down = (e: KeyboardEvent) => {
      if (e.key === "p" && (e.metaKey || e.ctrlKey)) {
        e.preventDefault()
        void setOpenData((currentOpen = false) => !currentOpen, {
          revalidate: false,
        })
      }
    }

    document.addEventListener("keydown", down)
    return () => {
      document.removeEventListener("keydown", down)
    }
  }, [setOpenData])

const filteredData = chartData.filter((item) => {
  const date = new Date(item.date)
  const referenceDate = new Date("2024-06-30")
  let daysToSubtract = 90
  if (timeRange === "30d") {
    daysToSubtract = 30
  } else if (timeRange === "7d") {
    daysToSubtract = 7
  }
  const startDate = new Date(referenceDate)
  startDate.setDate(startDate.getDate() - daysToSubtract)
  return date >= startDate
})

const grouped = useMemo(() => {
    return SAMPLE_DATA.mentionable.reduce(
      (acc, item) => {
        const isAvailable = !mentions.includes(item.title)

        if (isAvailable) {
          if (!acc[item.type]) {
            acc[item.type] = []
          }
          acc[item.type].push(item)
        }
        return acc
      },
      {} as Record<string, typeof SAMPLE_DATA.mentionable>
    )
  }, [mentions, SAMPLE_DATA])

useEffect(() => {
    Array.from(document.body.classList)
      .filter((className) => className.startsWith("theme-"))
      .forEach((className) => {
        document.body.classList.remove(className)
      })
    document.body.classList.add(`theme-${activeTheme}`)
    if (activeTheme.endsWith("-scaled")) {
      document.body.classList.add("theme-scaled")
    }
  }, [activeTheme])

return (
  <Alert
    data-variant={variant}
    className={cn(
      "mt-6 w-auto rounded-xl border-surface bg-surface text-surface-foreground md:-mx-1 **:[code]:border",
      className
    )}
    {...props}
  >
    {icon}
    {title && <AlertTitle>{title}</AlertTitle>}
    <AlertDescription className="text-card-foreground/80">
      {children}
    </AlertDescription>
  </Alert>
)

return (
  <div className="grid w-full max-w-md items-start gap-4" dir={dir}>
    {alerts.map((alert, index) => {
      const Icon = alert.icon
      return (
        <Alert key={index}>
          <Icon />
          <AlertTitle>{t[alert.titleKey]}</AlertTitle>
          <AlertDescription>{t[alert.descriptionKey]}</AlertDescription>
        </Alert>
      )
    })}
  </div>
)

return (
  <ChartContainer config={chartConfig} className="min-h-[200px] w-full">
    <BarChart accessibilityLayer data={chartData}>
      <CartesianGrid vertical={false} />
      <XAxis
        dataKey="month"
        tickLine={false}
        tickMargin={10}
        axisLine={false}
        tickFormatter={(value) => value.slice(0, 3)}
      />
      <Bar dataKey="desktop" fill="var(--color-desktop)" radius={4} />
      <Bar dataKey="mobile" fill="var(--color-mobile)" radius={4} />
    </BarChart>
  </ChartContainer>
)
